import heapq

def top_k(nums: list[float], k: int) -> list[float]:
    if k <= 0 or not nums:
        return []
    k = min(k, len(nums))
    heap = nums[:k]
    heapq.heapify(heap)
    for x in nums[k:]:
        if x > heap[0]:
            heapq.heapreplace(heap, x)
    return sorted(heap, reverse=True)
